--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -3428,6 +3428,57 @@
+// ─── Day/Night Cycle Visual Theme ─────────────────────────────────
+
+/**
+ * Get the current time of day as a normalized value between 0 and 1.
+ * 0 = midnight, 0.5 = noon, 1 = midnight again.
+ * Uses system clock hours and minutes.
+ * @returns number between 0 and 1 representing time of day
+ */
+export function getTimeOfDay(): number {
+  const now = new Date();
+  const hours = now.getHours();
+  const minutes = now.getMinutes();
+  // Convert to fractional hours
+  const fractionalHours = hours + minutes / 60;
+  // Normalize to [0,1]
+  return (fractionalHours % 24) / 24;
+}
+
+/**
+ * Apply visual theme to the canvas context based on time of day.
+ * Adjusts overlay opacity and color temperature to simulate day/night cycle.
+ * Night is darker with more reliance on torch lighting.
+ * @param ctx CanvasRenderingContext2D
+ * @param canvas HTMLCanvasElement
+ */
+export function applyTimeTheme(ctx: CanvasRenderingContext2D, canvas: HTMLCanvasElement) {
+  const time = getTimeOfDay();
+  // Calculate overlay opacity: brighter during day, darker at night
+  // Use a smooth curve: max brightness at 0.5 (noon), min at 0 and 1 (midnight)
+  const brightness = Math.cos(time * 2 * Math.PI) * 0.5 + 0.5; // 0 at midnight, 1 at noon
+
+  // Calculate overlay alpha for darkness: more alpha at night
+  const nightAlpha = 0.6 * (1 - brightness); // max 0.6 alpha at midnight
+
+  // Color temperature shift: warmer at night (more orange), neutral at day
+  // Interpolate between neutral (white) and warm orange tint
+  const warmTint = `rgba(255, 140, 60, ${nightAlpha * 0.3})`;
+  const darkOverlay = `rgba(0, 0, 30, ${nightAlpha})`;
+
+  // Draw dark overlay
+  ctx.save();
+  ctx.fillStyle = darkOverlay;
+  ctx.fillRect(0, 0, canvas.width, canvas.height);
+
+  // Draw warm tint overlay for torch-like glow at night
+  ctx.fillStyle = warmTint;
+  ctx.fillRect(0, 0, canvas.width, canvas.height);
+  ctx.restore();
+}
+
